{
  "abstain": false,
  "points": [
    {"text": "Allocate a tail‑latency budget (e.g., p95) for each downstream call and subtract it from the overall request deadline."},
    {"text": "Set the client timeout slightly above the sum of downstream budgets plus a safety margin (e.g., 10‑20% extra)."},
    {"text": "Limit retries to 1‑2 attempts and use exponential backoff with jitter to avoid thundering‑herd effects."},
    {"text": "Implement a circuit breaker that opens after a configurable error rate, preventing further retries during an outage."},
    {"text": "Use Little's Law (L = λ·W) to size request queues; ensure service concurrency does not exceed capacity under peak λ."},
    {"text": "Monitor TCP RTT, loss, and retransmission counts; spikes indicate network congestion that can inflate effective latency."},
    {"text": "Check for bufferbloat by measuring queueing delay on NICs and switches; high queuing can cause retransmissions and timeouts."},
    {"text": "Validate that TCP window scaling and receive buffers are sized for expected bandwidth‑delay product to avoid unnecessary retransmits."}
  ]
}

